        ["algo" => 478, "uuid" => "b9bfaa", "name" => "haetae", "type" => "signature", "status" => "active", "title" => "HAETAE", "description_md" => "HAETAE is a post-quantum digital signature scheme based on lattice problems, developed by Korean researchers as a Korean PQC standard candidate. Based on module-lattice problems similar to ML-DSA but with different design choices.\n\nHAETAE is the Korean Post-Quantum Cryptography standard candidate for digital signatures (KPQC competition). Designed to complement NIST standards for Korean sovereignty.", "mental_model" => "Korean lattice PQC signature -- KPQC competition candidate, module-lattice.", "purpose" => ["korean pqc lattice signature"], "good_for" => ["korean pqc compliance", "kpqc standard"], "avoid_for" => ["general (ml-dsa is fips 204 standard)"], "pros" => ["korean national pqc candidate", "lattice-based pq"], "cons" => ["not fips standard", "limited deployment"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Post-quantum lattice.", "post_quantum_status" => 5, "example" => ["scenario" => "Korean KPQC HAETAE signature", "input" => ["pk" => "haetae public key"], "output" => ["sig" => "haetae signature"]], "flow" => ["module-lattice signing similar to dilithium"], "related" => ["ml-dsa-65", "falcon-512"]],
