        ["algo" => 480, "uuid" => "40f3de", "name" => "picnic", "type" => "signature", "status" => "new", "title" => "Picnic", "description_md" => "Picnic is a post-quantum signature scheme based on zero-knowledge proofs of knowledge of a symmetric key (LowMC or AES). Security relies on the security of the symmetric cipher.\n\nPicnic was a NIST PQC alternate candidate. Relies on symmetric-cipher hardness (ZKBoo/ZKB++ framework). Unique security assumption but large signatures (10-200KB).", "mental_model" => "ZK proof of symmetric key PQ signature -- unique cipher-based security, large sigs.", "purpose" => ["symmetric-cipher based pq signature"], "good_for" => ["pqc research/diversity", "lowmc/aes cipher-based pq"], "avoid_for" => ["production (ml-dsa/falcon/slh-dsa preferred)", "large sig overhead"], "pros" => ["symmetric cipher security", "diverse assumption from lattice", "nist alternate"], "cons" => ["10-200KB signatures very large", "slow signing", "not standardized"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Post-quantum if symmetric cipher is PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "Picnic3 ZK PQ signature", "input" => ["lowmc_key" => "LowMC secret key", "message" => "data"], "output" => ["sig" => "10-50KB Picnic signature"]], "flow" => ["commit to lowmc/aes execution", "zk proof of knowledge (zkb++)", "n-party computation commitment"], "related" => ["ml-dsa-65", "sphincs+"]],
        ["algo" => 481, "uuid" => "5f36a6", "name" => "uov", "type" => "signature", "status" => "new", "title" => "UOV", "description_md" => "UOV (Unbalanced Oil and Vinegar) is a multivariate post-quantum signature scheme. Oil and vinegar variables create a trapdoor for signing. Base scheme underlying many multivariate signatures.\n\nUOV is a NIST PQC alternate candidate. Has compact signatures but large public keys (150KB+). Classic multivariate scheme -- Rainbow (which broke) was a layered UOV variant.", "mental_model" => "Multivariate UOV -- classic oil-and-vinegar PQ sig, large 150KB+ public key.", "purpose" => ["multivariate pq signature"], "good_for" => ["multivariate pqc diversity"], "avoid_for" => ["production (large pk)", "ml-dsa simpler and standard"], "pros" => ["compact signatures", "multivariate security assumption", "nist alternate"], "cons" => ["150KB+ public key", "multivariate implementation complex"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Post-quantum (multivariate).", "post_quantum_status" => 4, "example" => ["scenario" => "UOV multivariate signature", "input" => ["pk" => "150KB+ pk"], "output" => ["sig" => "96-byte signature"]], "flow" => ["oil-vinegar variable separation trapdoor", "sign by solving uov equations", "verify: evaluate public polynomials"], "related" => ["mayo", "rainbow", "ml-dsa-65"]],
        ["algo" => 482, "uuid" => "e736fd", "name" => "mayo", "type" => "signature", "status" => "new", "title" => "MAYO", "description_md" => "MAYO is a multivariate post-quantum signature scheme that improves upon UOV by using a whipping technique to reduce public key size. NIST PQC alternate candidate.\n\nMAYO-1 achieves 5.8KB public key (vs UOV 150KB+) while maintaining short signatures. Better practicality than standard UOV.", "mental_model" => "Improved UOV with 5.8KB public key -- NIST PQC alternate, smaller than UOV.", "purpose" => ["efficient multivariate pq signature"], "good_for" => ["multivariate pq with reasonable pk size"], "avoid_for" => ["standard (ml-dsa preferred)"], "pros" => ["5.8KB pk (much smaller than uov)", "short signatures", "nist alternate"], "cons" => ["not fips standard", "multivariate complexity"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Post-quantum multivariate.", "post_quantum_status" => 4, "example" => ["scenario" => "MAYO-1 signature", "input" => ["pk" => "5.8KB pk"], "output" => ["sig" => "321 bytes"]], "flow" => ["mayo whipping: embed uov map in larger space", "sign: solve mayo equations", "verify: mayo polynomial evaluation"], "related" => ["uov", "prov", "ml-dsa-44"]],
        ["algo" => 483, "uuid" => "32cbb8", "name" => "prov", "type" => "signature", "status" => "new", "title" => "PROV", "description_md" => "PROV (PRovable Unbalanced Oil and Vinegar) is a provably secure variant of UOV with tight security reduction. NIST PQC alternate candidate.\n\nPROV provides a tight security proof for the UOV structure with competitive key/signature sizes.", "mental_model" => "Provably secure UOV variant -- tighter security proof than standard UOV.", "purpose" => ["provably secure multivariate pq sig"], "good_for" => ["tight-security multivariate pq"], "avoid_for" => ["standard (ml-dsa)"], "pros" => ["tight security reduction", "uov-based pq"], "cons" => ["nist alternate (not fips)"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Post-quantum multivariate.", "post_quantum_status" => 4, "example" => ["scenario" => "PROV signature", "input" => ["pk" => "prov pk"], "output" => ["sig" => "prov sig"]], "flow" => ["tight-security uov sign/verify"], "related" => ["uov", "mayo"]],
        ["algo" => 484, "uuid" => "3e9f2a", "name" => "sqisign", "type" => "signature", "status" => "new", "title" => "SQISign", "description_md" => "SQISign (Short Quaternion and Isogeny Signature) is a post-quantum isogeny-based signature scheme. Extremely compact -- the smallest known PQ signature (177-byte sig, 64-byte pk).\n\nSQISign has the smallest PQ signatures of any known scheme but is extremely slow (minutes for signing on modern hardware). Based on supersingular isogeny Deuring correspondence. NIST alternate candidate.", "mental_model" => "Isogeny PQ signature -- world's smallest PQ sig (177 bytes) but minutes to sign.", "purpose" => ["smallest pq signature (bandwidth extreme)"], "good_for" => ["extreme bandwidth constrained pq (accept slow signing)", "isogeny pq research"], "avoid_for" => ["any performance requirement (minutes per sig)", "production (ml-dsa/falcon)"], "pros" => ["177-byte sig smallest pq", "64-byte pk tiny", "isogeny security assumption"], "cons" => ["minutes to sign on modern hardware", "not practical currently", "not fips"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Post-quantum (isogeny).", "post_quantum_status" => 4, "example" => ["scenario" => "SQISign ultra-compact PQ signature", "input" => ["pk" => "64 bytes"], "output" => ["sig" => "177 bytes"]], "flow" => ["isogeny walk on supersingular elliptic curves", "deuring correspondence trapdoor", "resp extremely slow"], "related" => ["ml-dsa-65", "falcon-512", "csidh"]],
