        ["algo" => 487, "uuid" => "fdc58c", "name" => "sdith", "type" => "signature", "status" => "new", "title" => "SDitH", "description_md" => "SDitH (Syndrome Decoding in the Head) is a post-quantum signature scheme based on the syndrome decoding problem (code-based hardness). Uses the MPC-in-the-head technique.\n\nSDitH is a NIST PQC alternate candidate using code-based (syndrome decoding) security assumption. Provides diversity from lattice-based signatures.", "mental_model" => "Code-based MPC-in-the-head PQ signature -- syndrome decoding hardness, NIST alternate.", "purpose" => ["code-based pq signature"], "good_for" => ["code-based pq sig diversity"], "avoid_for" => ["production (ml-dsa/falcon fips standard)"], "pros" => ["code-based pq assumption", "diverse from lattice", "nist alternate"], "cons" => ["not fips", "larger sigs than lattice"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 4, "example" => ["scenario" => "SDitH code-based PQ signature", "input" => ["pk" => "sdith pk"], "output" => ["sig" => "sdith sig"]], "flow" => ["mpc in the head", "syndrome decoding commitment", "fiat-shamir transform"], "related" => ["ml-dsa-65", "less", "picnic"]],
