        ["algo" => 490, "uuid" => "9f8c68", "name" => "cross", "type" => "signature", "status" => "new", "title" => "CROSS", "description_md" => "CROSS (Codes and Restricted Objects Signature Scheme) is a post-quantum signature based on the restricted error vector problem. NIST PQC alternate candidate.\n\nCROSS uses a variant of syndrome decoding with restricted error vectors for efficient signatures.", "mental_model" => "Restricted error code PQ signature -- NIST alternate, code-based.", "purpose" => ["restricted code pq signature"], "good_for" => ["code-based pq variant"], "avoid_for" => ["production (ml-dsa/falcon)"], "pros" => ["restricted error assumption", "nist alternate", "compact sigs"], "cons" => ["not fips", "limited deployment"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 4, "example" => ["scenario" => "CROSS signature", "input" => ["pk" => "cross pk"], "output" => ["sig" => "cross sig"]], "flow" => ["restricted error syndrome decode commitment"], "related" => ["sdith", "less"]],
