        ["algo" => 492, "uuid" => "cb402f", "name" => "gravity-sphincs", "type" => "signature", "status" => "new", "title" => "Gravity-SPHINCS", "description_md" => "Gravity-SPHINCS is an optimized variant of SPHINCS (predecessor to SPHINCS+/SLH-DSA) focused on faster signing. Based on the same hash-based hypertree structure.", "mental_model" => "Optimized SPHINCS variant -- faster signing hash-based, predecessor to SLH-DSA.", "purpose" => ["fast hash-based pq signature"], "good_for" => ["fast hash signing variant study"], "avoid_for" => ["production (use slh-dsa which is standardized)"], "pros" => ["faster signing than sphincs+", "hash-based pq"], "cons" => ["superseded by slh-dsa", "not fips"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Post-quantum hash-based.", "post_quantum_status" => 4, "example" => ["scenario" => "Gravity-SPHINCS signature", "input" => ["pk" => "small pk"], "output" => ["sig" => "hash sig"]], "flow" => ["optimized sphincs hypertree"], "related" => ["sphincs+", "slh-dsa-sha2-128f"]],
        ["algo" => 493, "uuid" => "b87e0d", "name" => "wots+", "type" => "signature", "status" => "new", "title" => "WOTS+", "description_md" => "WOTS+ (Winternitz One-Time Signature plus) is the one-time hash-based signature scheme used as the leaf primitive in XMSS and SPHINCS+/SLH-DSA. Not standalone -- used as a building block.\n\nWOTS+ is the one-time signature component inside XMSS trees and SPHINCS+ hypertrees. Each WOTS+ key pair can sign exactly one message -- the tree structures manage key reuse prevention.", "mental_model" => "Winternitz one-time hash signature -- building block for XMSS and SLH-DSA, not standalone.", "purpose" => ["hash-based one-time signature primitive"], "good_for" => ["understanding slh-dsa/xmss internals"], "avoid_for" => ["standalone use (use slh-dsa or xmss)"], "pros" => ["hash-only security", "xmss/slh-dsa component"], "cons" => ["one-time only", "not standalone", "managed by parent tree"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Post-quantum hash-based.", "post_quantum_status" => 5, "example" => ["scenario" => "WOTS+ leaf node in XMSS tree", "input" => ["priv" => "wots+ key", "message" => "data"], "output" => ["sig" => "wots+ one-time sig"]], "flow" => ["hash chain per message nibble", "signature = chain evaluations", "verify: chain forward to pubkey"], "related" => ["sphincs+", "slh-dsa-sha2-128f", "xmss", "fors"]],
        ["algo" => 494, "uuid" => "4d0114", "name" => "fors", "type" => "signature", "status" => "new", "title" => "FORS", "description_md" => "FORS (Forest of Random Subsets) is the few-time signature component in SPHINCS+/SLH-DSA. Signs the message digest using multiple Merkle trees of random subsets.\n\nFORS replaced HORST in SPHINCS+ by providing better security analysis. Used inside SLH-DSA as the message signing component before the hypertree authentication.", "mental_model" => "SPHINCS+/SLH-DSA few-time signature component -- replaces HORST, not standalone.", "purpose" => ["slh-dsa internal signature component"], "good_for" => ["understanding slh-dsa/sphincs+ structure"], "avoid_for" => ["standalone use (use slh-dsa)"], "pros" => ["better security than horst", "slh-dsa standard component"], "cons" => ["not standalone", "slh-dsa internal primitive"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Post-quantum hash-based.", "post_quantum_status" => 5, "example" => ["scenario" => "FORS signing inside SLH-DSA", "input" => ["message" => "slh-dsa msg digest"], "output" => ["fors_sig" => "forest authentication"]], "flow" => ["split message digest into k indices", "reveal leaves in k trees", "merkle auth paths for each"], "related" => ["sphincs+", "slh-dsa-sha2-128f", "wots+", "hors"]],
